var e=JSON.parse(`[{"id":"L2_1","type":"dialog","speaker":"ROOKIE_GRONIA_NULL_NULL","text":{"KOREA":"……네. 알겠습니다. 네.","JPN":"……はい。わかりました。はい。","ENG":"...Yes. Understood.","TWN":"……是，知道，好。"},"stage":{"bg":"DORMITORY_3","slots":{"L":null,"C":{"char_id":"ROOKIE_GRONIA_NULL_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L5_1","type":"dialog","speaker":"BASS_HARMONY_NULL_HIDE","text":{"KOREA":"중사님, 보안국이야? 레아는 괜찮대?","JPN":"軍曹さん、保安局から？　レアは大丈夫？","ENG":"Was it the National Security, Sergeant? Is Leah okay?","TWN":"中士，是安全局打來的嗎？蕾亞還好嗎？"},"stage":{"bg":"DORMITORY_3","slots":{"L":{"char_id":"ROOKIE_GRONIA_NULL_NULL","face":"UNIT_DESPAIR"},"C":null,"R":{"char_id":"BASS_HARMONY_NULL_HIDE","face":"UNIT_SURPRISE"}}}},{"id":"L6_1","type":"dialog","speaker":"ROOKIE_GRONIA_NULL_NULL","text":{"KOREA":"아뇨. 군에서 온 전화였어요.","JPN":"いいえ。軍からの電話でした。","ENG":"Nope. It was the military.","TWN":"不是，是軍隊打來的。"},"stage":{"bg":"DORMITORY_3","slots":{"L":{"char_id":"ROOKIE_GRONIA_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"BASS_HARMONY_NULL_HIDE","face":"UNIT_SURPRISE"}}}},{"id":"L7_1","type":"dialog","speaker":"ROOKIE_GRONIA_NULL_NULL","text":{"KOREA":"저더러 내일까지 방위 부대에 오라네요. 건국절 행사 때 경비 인력으로 차출하려나 봐요.","JPN":"明日まで防衛部隊にくるようにって言われました。建国記念日の行事に警備として送る予定みたいです。","ENG":"Told me to report to the Defense Unit by tomorrow. I guess they're going to send me to the National Foundation Day event as a security guard.","TWN":"叫我明天前到防衛隊報到，應該是因為國慶典禮需要比較多人力戒備吧？"},"stage":{"bg":"DORMITORY_3","slots":{"L":{"char_id":"ROOKIE_GRONIA_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"BASS_HARMONY_NULL_HIDE","face":"UNIT_SURPRISE"}}}},{"id":"L8_1","type":"dialog","speaker":"BASS_HARMONY_NULL_HIDE","text":{"KOREA":"그래……. 그렇구나…….","JPN":"そうか……そうなんだね……","ENG":"Oh... I see...","TWN":"喔喔……是喔……"},"stage":{"bg":"DORMITORY_3","slots":{"L":{"char_id":"ROOKIE_GRONIA_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"BASS_HARMONY_NULL_HIDE","face":"UNIT_DESPAIR"}}}},{"id":"L9_1","type":"dialog","speaker":"BASS_HARMONY_NULL_HIDE","text":{"KOREA":"레아는 왜 소식이 없는 걸까……? 나쁜 일에 휘말린 건 아니겠지?","JPN":"どうしてレアはなんの連絡もないのかしら……？　悪いことに巻き込まれてないわよね？","ENG":"Why hasn’t there been any news on Leah...? She hasn’t been caught up in anything horrible, has she?","TWN":"怎麼都沒有蕾亞的消息……？該不會發生什麼不好的事吧？"},"stage":{"bg":"DORMITORY_3","slots":{"L":{"char_id":"ROOKIE_GRONIA_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"BASS_HARMONY_NULL_HIDE","face":"UNIT_IDLE"}}}},{"id":"L11_1","type":"dialog","speaker":"ROOKIE_GRONIA_NULL_NULL","text":{"KOREA":"…….","JPN":"……","ENG":"…","TWN":"……"},"stage":{"bg":"DORMITORY_3","slots":{"L":null,"C":{"char_id":"ROOKIE_GRONIA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L14_1","type":"dialog","speaker":"ROOKIE_GRONIA_NULL_NULL","text":{"KOREA":"아아, 상상 친구 씨. 이럴 때 정말 싫다구요. 노골적으로 어떻게든 해 달라는 신호잖아요.","JPN":"ああ、エア友さん。こういう時が本当嫌なんだよ。明らかにどうにかしてって言う合図じゃない。","ENG":"Ahh, Mr. Imaginary Friend. This kind of situation really sucks! She’s clearly signaling to me to do something about it.","TWN":"哎呀～我想像中的朋友，我真的很討厭這種時候，這不是明擺著要我想點辦法嗎？"},"stage":{"bg":"BLACK","slots":{"L":null,"C":{"char_id":"ROOKIE_GRONIA_NULL_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L15_1","type":"dialog","speaker":"ROOKIE_GRONIA_NULL_NULL","text":{"KOREA":"하지만 <color=#ffd34c>무공 훈장을 받은 군인이라면</color> 같은 논리에는 이제 염증이 난단 말이죠.","JPN":"でも<color=#ffd34c>勲章を授与された軍人たるもの</color>、みたいな論理はもううんざり。","ENG":"Inflammatory logic beginning with <color=#ffd34c>being a decorated soldier</color> makes me feel sick now.","TWN":"但是<color=#ffd34c>身為一位授勳的軍人</color>，聽到這種話應該會立刻上火吧？"},"stage":{"bg":"BLACK","slots":{"L":null,"C":{"char_id":"ROOKIE_GRONIA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L16_1","type":"dialog","speaker":"ROOKIE_GRONIA_NULL_NULL","text":{"KOREA":"반역죄 운운한 시점에서 손가락 하나 잘못 까딱했다간 줄줄이 사형이걸랑요, 이거.","JPN":"反逆罪が言及された時点で指一本間違えたらみんな死刑なんだからね、これ。","ENG":"Since the accusation of treason came out, if we do one little thing wrong, it’s the death penalty for us all one after another.","TWN":"叛國罪這三個字一出現，就立刻將人五花大綁，然後就地正法！這樣才對吧？"},"stage":{"bg":"BLACK","slots":{"L":null,"C":{"char_id":"ROOKIE_GRONIA_NULL_NULL","face":"UNIT_PRIDE"},"R":null}}},{"id":"L19_1","type":"dialog","speaker":"OLD_GRONIA_NULL_NULL","text":{"KOREA":"레아는……. 우리 딸은 오늘도 안 오나요……?","JPN":"レアは……私の娘は今日も来ないんですか……？","ENG":"Leah... My daughter isn’t coming today as well...?","TWN":"蕾亞……我女兒今天也不回來嗎……？"},"stage":{"bg":"DORMITORY_3","slots":{"L":null,"C":{"char_id":"OLD_GRONIA_NULL_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L22_1","type":"dialog","speaker":"OLD_GRONIA_NULL_NULL","text":{"KOREA":"밖에서 나쁜 짓을 하고 돌아다닐 아이는 아닌데……. 나쁜 사람들에게 잡혀간 거면…….","JPN":"外で悪ふざけをする子じゃないのに……悪い人に捕まったら……","ENG":"She isn’t the rebellious type to go out and do bad things... What if some bad people took her...","TWN":"我女兒她不是那種會在外面惹事生非的壞孩子……萬一她被壞人抓走……"},"stage":{"bg":"DORMITORY_3","slots":{"L":{"char_id":"OLD_GRONIA_NULL_NULL","face":"UNIT_DESPAIR"},"C":null,"R":{"char_id":"BASS_HARMONY_NULL_HIDE","face":"UNIT_IDLE"}}}},{"id":"L23_1","type":"dialog","speaker":"BASS_HARMONY_NULL_HIDE","text":{"KOREA":"걱정 마세요, 아주머니. 레아는 무사할 거예요.","JPN":"大丈夫ですよ、おばさん。レアはきっと無事です。","ENG":"Don’t worry, Madam. Leah will be fine.","TWN":"伯母，你放心，蕾亞沒事的。"},"stage":{"bg":"DORMITORY_3","slots":{"L":{"char_id":"OLD_GRONIA_NULL_NULL","face":"UNIT_DESPAIR"},"C":null,"R":{"char_id":"BASS_HARMONY_NULL_HIDE","face":"UNIT_LAUGH"}}}},{"id":"L24_1","type":"dialog","speaker":"BASS_HARMONY_NULL_HIDE","text":{"KOREA":"그렇지, 중사님?","JPN":"そうよね、軍曹さん？","ENG":"Isn’t that right, Sergeant?","TWN":"你說是不是，中士？"},"stage":{"bg":"DORMITORY_3","slots":{"L":{"char_id":"OLD_GRONIA_NULL_NULL","face":"UNIT_DESPAIR"},"C":null,"R":{"char_id":"BASS_HARMONY_NULL_HIDE","face":"UNIT_IDLE"}}}},{"id":"L26_1","type":"dialog","speaker":"ROOKIE_GRONIA_NULL_NULL","text":{"KOREA":"아, 어. ……네.","JPN":"え、あ。……はい。","ENG":"Ah, well... Right.","TWN":"蛤？喔 ……是。"},"stage":{"bg":"DORMITORY_3","slots":{"L":null,"C":{"char_id":"ROOKIE_GRONIA_NULL_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L29_1","type":"dialog","speaker":"OLD_GRONIA_NULL_NULL","text":{"KOREA":"손님에게 죄송해서 어떡해…….","JPN":"お客さんに申し訳ないわ……","ENG":"With such a special guest here. I’m so sorry...","TWN":"怎麼辦，對客人這麼失禮……"},"stage":{"bg":"DORMITORY_3","slots":{"L":{"char_id":"OLD_GRONIA_NULL_NULL","face":"UNIT_DESPAIR"},"C":null,"R":{"char_id":"BASS_HARMONY_NULL_HIDE","face":"UNIT_IDLE"}}}},{"id":"L30_1","type":"dialog","speaker":"OLD_GRONIA_NULL_NULL","text":{"KOREA":"나라를 위해 싸우는 훌륭한 군인 분인데 이런 마당에 모셔서…….","JPN":"国のために戦ってくれてる立派な軍人さんなのに、こんなところに来てもらっちゃって……","ENG":"A great soldier fighting for our country and she’s here in such a bad situation...","TWN":"人家是對國家有貢獻的軍人，我們這樣招呼不周……"},"stage":{"bg":"DORMITORY_3","slots":{"L":{"char_id":"OLD_GRONIA_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"BASS_HARMONY_NULL_HIDE","face":"UNIT_IDLE"}}}},{"id":"L32_1","type":"dialog","speaker":"ROOKIE_GRONIA_NULL_NULL","text":{"KOREA":"…….","JPN":"……","ENG":"…","TWN":"……"},"stage":{"bg":"DORMITORY_3","slots":{"L":null,"C":{"char_id":"ROOKIE_GRONIA_NULL_NULL","face":"UNIT_PRIDE"},"R":null}}}]`);export{e as default};